#include <iostream>
using namespace std;

// Static allocation: size must be known at compile time
int fixedArray[100];  // OK

int main() {
    int n;
    cout << "Enter array size: ";
    cin >> n;

    // int bad[n]; // VLA not standard in C++ (though some compilers allow)
    // Instead, dynamic allocation:
    int* dynArray = new int[n];  // allocate array of size n at runtime

    for (int i = 0; i < n; i++) {
        dynArray[i] = i * 10;
    }

    for (int i = 0; i < n; i++) {
        cout << dynArray[i] << " ";
    }
    cout << endl;

    delete[] dynArray;  // must free
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    // Allocate a single integer on heap
    int* p = new int;      // uninitialized
    *p = 42;
    cout << "Value: " << *p << endl;

    // Allocate and initialize
    int* q = new int(100);  // direct initialization
    cout << "Initialized: " << *q << endl;

    // Allocate with uniform initialization (C++11)
    int* r = new int{200};
    cout << "Uniform init: " << *r << endl;

    // Free memory
    delete p;
    delete q;
    delete r;

    // After delete, pointer becomes dangling (still holds old address)
    // Setting to nullptr is good practice
    p = nullptr;
    q = nullptr;
    r = nullptr;

    return 0;
}

#include <iostream>
