    return 0;
}

#include <iostream>
using namespace std;

class Student {
public:
    string name;
    int id;

    Student(string n, int i) : name(n), id(i) {
        cout << "Constructor called for " << name << endl;
    }

    ~Student() {
        cout << "Destructor called for " << name << endl;
    }

    void display() {
        cout << "Student: " << name << ", ID: " << id << endl;
    }
};

int main() {
    // Allocate single object
    Student* s1 = new Student("Alice", 101);
    s1->display();
    delete s1;  // calls destructor

    // Allocate array of objects
    Student* classRoom = new Student[3]{
        {"Bob", 201},
        {"Charlie", 202},
        {"Diana", 203}
    };

    for (int i = 0; i < 3; i++) {
        classRoom[i].display();
    }

    delete[] classRoom;  // calls destructor for each

    return 0;
}

#include <iostream>
using namespace std;

void leakExample() {
    int* p = new int[1000];
    // forgot delete[] p;
    // When function exits, pointer p is destroyed, but the heap memory is lost.
}

int main() {
    // This loop would cause massive leak if uncommented
    // for (int i = 0; i < 100000; i++) {
    //     leakExample();
    // }

    // Correct way: always delete
    int* data = new int(42);
    cout << *data << endl;
    delete data;   // no leak
    data = nullptr;

    // Tools to detect leaks: Valgrind, AddressSanitizer, Visual Studio's debug heap
    cout << "No leak in this example" << endl;
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int* p = new int(5);
    delete p;

    // p now dangling: points to freed memory
    // *p = 10;  // VERY BAD: undefined behavior

    // Solution: set to nullptr after delete
    p = nullptr;

    if (p != nullptr) {
        *p = 10;  // safe now
    } else {
        cout << "Pointer is null, can't dereference" << endl;
    }

    // Another danger: two pointers to same memory
    int* q = new int(42);
    int* r = q;  // both point to same
    delete q;
    // r is now dangling too!
    r = nullptr; // need to set both

    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int* p = new int(5);
    delete p;
    // delete p;  // ERROR: double delete, crashes

    // Safe pattern:
    int* q = new int(10);
    delete q;
    q = nullptr;
    delete q;  // safe: deleting nullptr does nothing

    cout << "Double delete on nullptr is fine" << endl;
    return 0;
}

#include <iostream>
using namespace std;

int main() {
    int rows = 3, cols = 4;

    // Method 1: array of pointers (jagged possible)
    int** matrix = new int*[rows];
    for (int i = 0; i < rows; i++) {
        matrix[i] = new int[cols];
        for (int j = 0; j < cols; j++) {
            matrix[i][j] = i * cols + j;
        }
    }

    // Print
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            cout << matrix[i][j] << "\t";
        }
        cout << endl;
    }

    // Deallocate (reverse order)
    for (int i = 0; i < rows; i++) {
        delete[] matrix[i];
    }
    delete[] matrix;

    // Method 2: flat array
    int* flat = new int[rows * cols];
    for (int i = 0; i < rows; i++) {
        for (int j = 0; j < cols; j++) {
            flat[i * cols + j] = i * cols + j;
        }
    }

    // Access flat[i][j] as flat[i*cols + j]
    delete[] flat;

    return 0;
}

#include <iostream>
#include <cstdlib>
using namespace std;

class Test {
public:
    Test() { cout << "Constructor" << endl; }
    ~Test() { cout << "Destructor" << endl; }
};

int main() {
    // C++ way
    Test* t1 = new Test();   // calls constructor
    delete t1;               // calls destructor

    // C way (don't do this in C++ for objects)
    Test* t2 = (Test*)malloc(sizeof(Test)); // no constructor
    // ... use t2 ...
    free(t2);  // no destructor

    // For primitive types, both work, but new/delete is idiomatic C++
    int* p = new int(5);
    delete p;

    int* q = (int*)malloc(sizeof(int));
    *q = 5;
    free(q);

    return 0;
}

#include <iostream>
#include <new>  // for nothrow
using namespace std;

int main() {
    // Normal new throws exception
    try {
        int* huge = new int[100000000000]; // might throw
        delete[] huge;
    } catch (const bad_alloc& e) {
        cout << "Exception: " << e.what() << endl;
    }

    // nothrow new returns nullptr on failure
    int* p = new(nothrow) int[100000000000];
    if (p == nullptr) {
        cout << "Allocation failed, returned nullptr" << endl;
    } else {
        delete[] p;
    }

    return 0;
}

#include <iostream>
#include <new>  // placement new
using namespace std;

class Point {
public:
    int x, y;
    Point(int a, int b) : x(a), y(b) {
        cout << "Point constructed at " << this << endl;
    }
    ~Point() { cout << "Point destroyed" << endl; }
};

int main() {
    // Allocate raw memory (not initialized)
    char* buffer = new char[sizeof(Point)];

    // Construct Point in that memory
    Point* p = new(buffer) Point(10, 20);

    cout << "Point values: " << p->x << ", " << p->y << endl;

    // Must call destructor explicitly (placement new requires explicit destructor)
    p->~Point();

    // Delete raw memory
    delete[] buffer;

    return 0;
}
